const p = msg.topic.split('/');
if (p.length < 5) return null;
const serial = p[3];
const d = msg.payload || {};

const info = {
    device_type:      d.device_type      || '',
    production_date:  d.production_date  || '',
    hw_version:       d.hw_version       || 0,
    firmware_version: d.firmware_version || 0,
    manufacturer_id:  d.manufacturer_id  || '',
    equalization_voltage_mv: d.equalization_voltage_mv || 0,
    boost_voltage_mv:        d.boost_voltage_mv        || 0,
    float_voltage_mv:        d.float_voltage_mv        || 0,
    temp_comp_mv_per_c:      d.temp_comp_mv_per_c      || 0,
    serial_number: serial
};

const fleet = global.get('fleet') || {};
if (!fleet[serial]) fleet[serial] = {};
fleet[serial].info = info;
global.set('fleet', fleet);

const zone = p[1], gw = p[2];
msg.payload = [{
    measurement: 'device_info',
    tags: { serial, zone, gateway_id: gw, hw_version: String(info.hw_version) },
    fields: {
        firmware_version:       info.firmware_version,
        boost_voltage_v:        info.boost_voltage_mv        / 1000,
        float_voltage_v:        info.float_voltage_mv        / 1000,
        equalization_voltage_v: info.equalization_voltage_mv / 1000,
        temp_comp_mv_per_c:     info.temp_comp_mv_per_c,
        production_date:        info.production_date
    }
}];
return msg;

const p = msg.topic.split('/');
if (p.length < 5) return null;
const serial = p[3];
const d = msg.payload || {};

const en = (v, map) => {
    if (typeof v === 'number') return v;
    if (typeof v === 'string') return map[v] !== undefined ? map[v] : (parseInt(v) || 0);
    return 0;
};

const settings = {
    serial,
    battery_type:            en(d.battery_type, { "BATTERY_AGM":1, "BATTERY_LIQUID":2, "BATTERY_LFP":3, "BATTERY_LFP_HIGH_TEMP":4, "BATTERY_LFP_MEDIUM_TEMP":5, "BATTERY_LFP_LOW_TEMP":6 }),
    capacity_ah:             d.capacity_ah             || 100,
    lvd_voltage_mv:          d.lvd_voltage_mv          || 11000,
    lvd_mode:                en(d.lvd_mode, { "LVD_MODE_SOC":0, "LVD_MODE_VOLTAGE":1 }),
    night_mode:              en(d.night_mode, { "NIGHT_MODE_ALWAYS_ON":0, "NIGHT_MODE_D2D":1, "NIGHT_MODE_DD":2, "NIGHT_MODE_MN":3 }),
    evening_minutes:         d.evening_minutes         || 0,
    morning_minutes:         d.morning_minutes         || 0,
    night_threshold_mv:      d.night_threshold_mv      || 11500,
    dimming_mode:            en(d.dimming_mode, { "NIGHT_MODE_ALWAYS_ON":0, "NIGHT_MODE_D2D":1, "NIGHT_MODE_DD":2, "NIGHT_MODE_MN":3 }),
    evening_minutes_dimming: d.evening_minutes_dimming || 0,
    morning_minutes_dimming: d.morning_minutes_dimming || 0,
    dimming_pct:             d.dimming_pct             || 100,
    base_dimming_pct:        d.base_dimming_pct        || 30,
    advanced_flags:          d.advanced_flags          || 0
};

const fleet = global.get('fleet') || {};
if (!fleet[serial]) fleet[serial] = {};
fleet[serial].settings = settings;
global.set('fleet', fleet);

const selected = global.get('selected_serial');
if (selected === serial) {
    // Check if the Control tab has unsaved changes for this specific device.
    // Dashboard variables are per-tab, so we rely on 'w__dirty' flag set in tab-control.
    // However, fn-cache-settings is in tab-ingestion, so it can't see flow.get('w__dirty').
    // We'll use a global flag or just trust that fn-on-device-select handles the block.
    msg.payload = serial;
    return msg;
}
return null;

const p = msg.topic.split('/');
const serial = p[3];
const zone = p[1];
const isOnline = msg.payload.toString().trim() === '1';
const key = 'online_' + serial;
const wasOnline = context.get(key);
context.set(key, isOnline);

const onlineMap = global.get('online_map') || {};
onlineMap[serial] = { online: isOnline, ts: new Date().toISOString() };
global.set('online_map', onlineMap);

if (!isOnline && wasOnline !== false) {
    const ts = new Date().toISOString();
    return [{ payload: {
        severity: 'critical', condition: 'Device offline',
        emailNeeded: true, serial, zone, ts,
        subject: '[MPPT CRITICAL] ' + serial + ' offline',
        body: 'Device ' + serial + ' (zone: ' + zone + ') went offline at ' + ts
    }}];
}
if (isOnline && wasOnline === false) {
    node.log(serial + ' back online');
}
return null;

if (!msg.payload || !msg.payload.subject) return null;
msg.topic = msg.payload.subject;
msg.payload = msg.payload.body;
return msg;

const bat = msg.bat, load = msg.load;
const f = msg.faults || {};
const serial = msg.serial, zone = msg.zone;
const ts = msg.gen.timestamp || new Date().toISOString();

const mask = f.fault_mask || 0;
const bit = (n) => !!(mask & (1 << n));

const checks = [
    { cond: bat.soc_pct >= 10 && bat.soc_pct < 20, sev: 'warning',  email: false, msg: 'Battery SOC low (' + bat.soc_pct + '%)' },
    { cond: bat.soc_pct < 10,                       sev: 'critical', email: true,  msg: 'Battery SOC critical (' + bat.soc_pct + '%)' },
    { cond: bit(4) || load.lvd_active,               sev: 'critical', email: true,  msg: 'LVD active' },
    { cond: bit(0), sev: 'critical', email: true,  msg: 'Battery over voltage' },
    { cond: bit(5), sev: 'critical', email: true,  msg: 'Over discharge current' },
    { cond: bit(6), sev: 'critical', email: true,  msg: 'Battery over temperature' },
    { cond: bit(7), sev: 'critical', email: true,  msg: 'Battery under temperature' }
];

const out = checks.filter(c => c.cond).map(c => ({ payload: {
    severity: c.sev, condition: c.msg, emailNeeded: c.email,
    serial, zone, ts,
    subject: '[MPPT ' + c.sev.toUpperCase() + '] ' + serial + ' - ' + c.msg,
    body: 'Device: ' + serial + '\nZone: ' + zone + '\nCondition: ' + c.msg + '\nTimestamp: ' + ts
}}));

if (!out.length) return null;
const email = out.filter(m => m.payload.emailNeeded);
return [ email.length ? email : null, out ];

const num = (v, d=0) => typeof v === 'number' ? v : d;
const tags = {
    zone: msg.zone, gateway_id: msg.gateway_id, serial: msg.serial,
    hw_version: msg.hw_version || '0',
    charge_mode: msg.bat.charge_mode || 'Float'
};
const fields = {
    voltage_v:           num(msg.bat.voltage_v),
    soc_pct:             num(msg.bat.soc_pct),
    charge_current_a:    num(msg.bat.charge_current_a),
    charge_power_w:      num(msg.bat.charge_power_w),
    is_night:            msg.bat.is_night ? 1 : 0,
    energy_in_daily_wh:  num(msg.bat.energy_in_daily_wh),
    energy_out_daily_wh: num(msg.bat.energy_out_daily_wh),
    energy_retained_wh:  num(msg.bat.energy_retained_wh),
    load_on:             msg.load.load_on ? 1 : 0,
    lvd_active:          (msg.load.lvd_active || (msg.faults && msg.faults.lvd_active)) ? 1 : 0,
    load_current_a:      num(msg.load.current_a),
    load_power_w:        num(msg.load.power_w),
    pv_voltage_v:        num(msg.pv.voltage_v),
    pv_target_voltage_v: num(msg.pv.target_voltage_v),
    internal_temp_c:     num(msg.gen.internal_temp_c),
    external_temp_c:     num(msg.gen.external_temp_c),
    led_voltage_v:       num(msg.led.voltage_v),
    led_current_a:       num(msg.led.current_a),
    led_power_w:         num(msg.led.power_w)
};
msg.payload = [fields, tags];
return msg;

const num = (v, d=0) => typeof v === 'number' ? v : d;
const f = msg.faults || {};
const load = msg.load || {};

const fields = {
    fault_mask:             num(f.fault_mask),
    any_fault:              (f.any_fault || f.fault_mask) ? 1 : 0,
    battery_over_voltage:   num(f.battery_over_voltage),
    pv_over_voltage:        num(f.pv_over_voltage),
    controller_over_temp:   num(f.controller_over_temp),
    charge_over_current:    num(f.charge_over_current),
    lvd_active:             num(f.lvd_active) || (load.lvd_active ? 1 : 0),
    over_discharge_current: num(f.over_discharge_current),
    battery_over_temp:      num(f.battery_over_temp),
    battery_under_temp:     num(f.battery_under_temp)
};

const tags = {
    zone: msg.zone, gateway_id: msg.gateway_id,
    serial: msg.serial, hw_version: msg.hw_version || '0'
};

msg.payload = [fields, tags];
return msg;

const p = msg.topic.split('/');
if (p.length < 5) return null;
const zone = p[1], gw = p[2], serial = p[3];

const d = msg.payload || {};
const mask = d.faultMask || d.fault_mask || 0;

const FAULT_NAMES = [
    'battery_over_voltage',
    'pv_over_voltage',
    'controller_over_temp',
    'charge_over_current',
    'lvd_active',
    'over_discharge_current',
    'battery_over_temp',
    'battery_under_temp'
];

const fleet = global.get('fleet') || {};
const info = (fleet[serial] && fleet[serial].info) || {};

const fields = { fault_mask: mask, any_fault: mask !== 0 ? 1 : 0 };
FAULT_NAMES.forEach((name, i) => { fields[name] = (mask >> i) & 1; });

const faultMap = global.get('fault_map') || {};
faultMap[serial] = { fault_mask: mask, any_fault: mask !== 0, ...fields };
global.set('fault_map', faultMap);

if (fleet[serial]) {
    fleet[serial].faults = faultMap[serial];
    global.set('fleet', fleet);
}

const influxMsg = Object.assign({}, msg, {
    payload: [fields, {
        serial, zone, gateway_id: gw,
        hw_version: String(info.hw_version || 0)
    }]
});

const prev = context.get('prev_mask') || 0;
context.set('prev_mask', mask);
const newBits = mask & ~prev;

let alertMsg = null;
if (newBits !== 0) {
    const active = FAULT_NAMES.filter((_, i) => (newBits >> i) & 1);
    const ts = new Date().toISOString();
    alertMsg = { payload: {
        severity: 'critical', emailNeeded: true,
        condition: 'Fault(s) active: ' + active.join(', '),
        serial, zone, ts,
        subject: '[MPPT FAULT] ' + serial + ' — ' + active[0],
        body: 'Device: ' + serial + '\nZone: ' + zone + '\nFaults: ' + active.join(', ') + '\nTimestamp: ' + ts
    }};
}

return [influxMsg, alertMsg];

const p = msg.topic.split('/');
if (p.length < 5) return null;
msg.zone       = p[1];
msg.gateway_id = p[2];
msg.serial     = p[3];

const d = msg.payload || {};

const flags = d.flags || 0;
const bit   = (v, n) => !!(v & (1 << n));
const mv2v  = mv  => (mv  || 0) / 1000;
const ma2a  = ma10 => (ma10 || 0) / 100;

const fleet = global.get('fleet') || {};
const info = (fleet[msg.serial] && fleet[msg.serial].info) || {};
const hw_version = info.hw_version || 0;
msg.hw_version = String(hw_version);

msg.gen = {
    hw_version,
    firmware_version:   info.firmware_version || 0,
    internal_temp_c:    d.internal_temp_c  || 0,
    external_temp_c:    d.external_temp_c  || 0,
    controller_op_days: d.controller_op_days || 0,
    timestamp: new Date().toISOString()
};

msg.bat = {
    voltage_v:               mv2v(d.battery_voltage_mv),
    soc_pct:                 d.battery_soc_pct  || 0,
    charge_current_a:        ma2a(d.charge_current_ma10),
    charge_power_w:          d.charge_power_w   || 0,
    end_of_charge_voltage_v: mv2v(d.end_of_charge_voltage_mv),
    charge_mode:             ['Float','Boost','Equalization','Disabled'][d.charge_mode || 0] || 'Float',
    is_night:                bit(flags, 1),
    bat_op_days:             d.bat_op_days      || 0,
    energy_in_daily_wh:      d.energy_in_daily_wh  || 0,
    energy_out_daily_wh:     d.energy_out_daily_wh || 0,
    energy_retained_wh:      d.energy_retained_wh  || 0,
    detected: bit(flags, 0)
};

msg.load = {
    load_on:         bit(flags, 2),
    night_mode:      bit(flags, 3),
    lvd_active:      bit(flags, 4),
    user_disconnect: bit(flags, 5),
    over_current:    bit(flags, 6),
    current_a:       ma2a(d.load_current_ma10),
    power_w:         d.load_power_w || 0
};

msg.pv = {
    voltage_v:        mv2v(d.pv_voltage_mv),
    target_voltage_v: mv2v(d.pv_target_voltage_mv),
    detected: bit(flags, 7)
};

msg.night = {
    time_since_dusk_min: d.time_since_dusk_min || 0,
    average_length_min:  d.average_length_min  || 0
};

msg.led = {
    voltage_v:   mv2v(d.led_voltage_mv),
    current_a:   ma2a(d.led_current_ma10),
    power_w:     d.led_power_w || 0,
    status:      ['Normal','Short','Open'][d.led_status || 0] || 'Normal',
    dali_active: bit(flags, 8)
};

const faultMap = global.get('fault_map') || {};
msg.faults = faultMap[msg.serial] || { fault_mask: 0, any_fault: false };

fleet[msg.serial] = {
    serial: msg.serial, zone: msg.zone, gateway_id: msg.gateway_id,
    hw_version: msg.hw_version,
    bat: msg.bat, load: msg.load, pv: msg.pv,
    faults: msg.faults, gen: msg.gen, ts: msg.gen.timestamp,
    info: info,
    settings: fleet[msg.serial] ? fleet[msg.serial].settings || {} : {}
};
global.set('fleet', fleet);
return msg;

const p = msg.topic.split("/");
if (p.length < 5) return null;
const zone = p[1], gateway = p[2], serial = p[3], type = p[p.length-1];
const dl = msg.payload;
if (!dl || typeof dl !== "object") return null;
const num = v => (typeof v === "number" ? v : 0);
const fleet = global.get("fleet") || {};
const info = (fleet[serial] && fleet[serial].info) || {};
const hw_version = String(info.hw_version || 0);
const ct = { serial, gateway_id: gateway, zone, hw_version };

function unpackStateFlags(sf) {
    return {
        flag_load_disconnect:  (sf >> 0) & 1, flag_full_charge:       (sf >> 1) & 1,
        flag_pv_over_current:  (sf >> 2) & 1, flag_load_over_current: (sf >> 3) & 1,
        flag_bat_over_voltage: (sf >> 4) & 1, flag_low_soc:           (sf >> 5) & 1,
        flag_temp_pv_over:     (sf >> 6) & 1, flag_temp_pv_low:       (sf >> 7) & 1,
        flag_temp_load_over:   (sf >> 8) & 1
    };
}

function mapEntry(e, i, indexKey) {
    return {
        [indexKey]:      num(e.index),
        vbat_min_v:      num(e.vbat_min_mv)   / 1000,
        vbat_max_v:      num(e.vbat_max_mv)   / 1000,
        vpv_min_v:       num(e.vpv_min_mv)    / 1000,
        vpv_max_v:       num(e.vpv_max_mv)    / 1000,
        ah_charge:       num(e.ah_charge_mah) / 1000,
        ah_load:         num(e.ah_load_mah)   / 1000,
        soc_pct:         num(e.soc_pct),
        ext_temp_max_c:  num(e.ext_temp_max_c),
        ext_temp_min_c:  num(e.ext_temp_min_c),
        nightlength_min: num(e.nightlength_min),
        il_max_a:        num(e.il_max_ma10)   / 100,
        ipv_max_a:       num(e.ipv_max_ma10)  / 100,
        ...unpackStateFlags(num(e.state_flags))
    };
}

let summary = null, daily = null, monthly = null;

if (type === "summary") {
    summary = [{ measurement: "datalogger_summary", payload: [{
        recorded_days:              num(dl.recorded_days),
        days_with_lvd:              num(dl.days_with_lvd),
        months_without_full_charge: num(dl.months_without_full_charge),
        avg_morning_soc_pct:        num(dl.avg_morning_soc_pct) / 100,
        total_ah_charge:            num(dl.total_ah_charge_mah) / 1000,
        total_ah_load:              num(dl.total_ah_load_mah)   / 1000
    }, ct]}];
}

if (type === "daily") {
    daily = (dl.daily_logs || []).map((e, i) => ({
        measurement: "datalogger_daily",
        payload: [mapEntry(e, i, "day_num"), Object.assign({ day_index: String(i+1) }, ct)]
    }));
}

if (type === "monthly") {
    monthly = (dl.monthly_logs || []).map((e, i) => ({
        measurement: "datalogger_monthly",
        payload: [mapEntry(e, i, "month_num"), Object.assign({ month_index: String(i+1) }, ct)]
    }));
}

return [summary, daily, monthly];

const fleet = global.get('fleet') || {};
const onlineMap = global.get('online_map') || {};
const serials = Object.keys(fleet).sort();

if (!serials.length) {
    const empty = '<p style="color:#94a3b8;padding:24px;text-align:center;font-style:italic">No devices detected on the network yet.</p>';
    return [{ payload: empty }, { payload: empty }];
}

let totalDevices = serials.length;
let onlineCount = 0;
let faultCount = 0;
let totalSoc = 0;
let totalCharge = 0;

for (const s of serials) {
    const d = fleet[s];
    const om = onlineMap[s];
    if (!om || om.online) onlineCount++;
    if (d.faults && (d.faults.any_fault || Object.values(d.faults).some(v => v === 1 || v === true))) faultCount++;
    totalSoc += (d.bat && typeof d.bat.soc_pct === 'number') ? d.bat.soc_pct : 0;
    totalCharge += (d.bat && typeof d.bat.charge_power_w === 'number') ? d.bat.charge_power_w : 0;
}

const avgSoc = totalDevices ? Math.round(totalSoc / totalDevices) : 0;
const offlineCount = totalDevices - onlineCount;

function statCard(label, value, sub, color) {
    return '<div style="display:flex; flex-direction:column; align-items:center; justify-content:center; background:rgba(30, 41, 59, 0.7); border:1px solid #334155; border-radius:12px; padding:20px; margin:8px; min-width:160px; flex:1; box-shadow:0 4px 6px -1px rgb(0 0 0 / 0.1)">' +
        '<div style="font-size:32px; font-weight:800; color:' + color + '; line-height:1">' + value + '</div>' +
        '<div style="font-size:13px; font-weight:600; color:#94a3b8; margin-top:8px; text-transform:uppercase; letter-spacing:0.05em">' + label + '</div>' +
        (sub ? '<div style="font-size:11px; color:#64748b; margin-top:2px">' + sub + '</div>' : '') +
        '</div>';
}

const summaryHtml = '<div style="display:flex; flex-wrap:wrap; justify-content:space-between; width:100%">' +
    statCard('Devices', totalDevices, 'total', '#3b82f6') +
    statCard('Online', onlineCount, 'online', '#22c55e') +
    statCard('Faults', faultCount, 'warning', '#ef4444') +
    statCard('Avg SOC', avgSoc + '%', 'fleet avg', '#f59e0b') +
    '</div>';

let tableHtml = '<table style="width:100%; border-collapse:collapse; color:#e2e8f0; font-size:14px">' +
    '<thead style="background:rgba(15, 23, 42, 0.5); text-align:left">' +
    '<tr>' +
    '<th style="padding:12px 16px">Serial</th>' +
    '<th style="padding:12px 16px">Status</th>' +
    '<th style="padding:12px 16px">Vbat</th>' +
    '<th style="padding:12px 16px">SOC</th>' +
    '<th style="padding:12px 16px">Charge</th>' +
    '<th style="padding:12px 16px">Load</th>' +
    '<th style="padding:12px 16px">Last Seen</th>' +
    '</tr></thead><tbody>';

for (const s of serials) {
    const d = fleet[s];
    const om = onlineMap[s];
    const isOnline = !om || om.online;
    const statusColor = isOnline ? '#22c55e' : '#ef4444';
    const lastSeen = om ? new Date(om.ts).toLocaleTimeString() : '—';

    tableHtml += '<tr style="border-bottom:1px solid #334155; transition:background 0.2s" onmouseover="this.style.background=\'rgba(51, 65, 85, 0.3)\'" onmouseout="this.style.background=\'transparent\'">' +
        '<td style="padding:12px 16px; font-weight:700">' + s + '</td>' +
        '<td style="padding:12px 16px"><span style="display:inline-block; width:8px; height:8px; border-radius:50%; background:' + statusColor + '; margin-right:8px"></span>' + (isOnline ? 'Online' : 'Offline') + '</td>' +
        '<td style="padding:12px 16px">' + (d.bat ? d.bat.voltage_v.toFixed(2) + ' V' : '—') + '</td>' +
        '<td style="padding:12px 16px">' + (d.bat ? d.bat.soc_pct + '%' : '—') + '</td>' +
        '<td style="padding:12px 16px">' + (d.bat ? d.bat.charge_power_w + ' W' : '—') + '</td>' +
        '<td style="padding:12px 16px">' + (d.load ? d.load.power_w + ' W' : '—') + '</td>' +
        '<td style="padding:12px 16px; color:#64748b">' + lastSeen + '</td>' +
        '</tr>';
}
tableHtml += '</tbody></table>';

return [{ payload: summaryHtml }, { payload: tableHtml }];

const serial = msg.payload;
const out = new Array(18).fill(null);
const currentSerial = global.get('selected_serial');

if (!serial || typeof serial !== 'string') {
    global.set('selected_serial', null);
    flow.set('baseline', null);
    flow.set('ui_state', {});
    node.send(out);
    return null;
}

global.set('selected_serial', serial);

const fleet = global.get('fleet') || {};
const dev = fleet[serial] || {};
const s = dev.settings || null;
const info = dev.info || {};

// UPDATE BASELINE:
// If we just switched to this device OR if we are currently clean (no unsaved edits),
// we update the baseline to match the latest device state.
if (serial !== currentSerial || !flow.get('w__dirty')) {
    flow.set('baseline', s ? JSON.parse(JSON.stringify(s)) : null);

    // Also reset the UI state to match the new baseline
    const ui = {};
    if (s) {
        ui['w-bat-type']     = String(s.battery_type || 0);
        ui['w-cap-ah']       = s.capacity_ah || 100;
        ui['w-lvd-v']        = (s.lvd_voltage_mv || 11000) / 1000;
        ui['w-lvd-mode']     = s.lvd_mode === 1;
        ui['w-night-mode']   = String(s.night_mode || 1);
        ui['w-eve-min']      = s.evening_minutes || 0;
        ui['w-morn-min']     = s.morning_minutes || 0;
        ui['w-night-thresh'] = (s.night_threshold_mv || 11500) / 1000;
        ui['w-dim-mode']     = String(s.dimming_mode || 0);
        ui['w-dim-eve-min']  = s.evening_minutes_dimming || 0;
        ui['w-dim-morn-min'] = s.morning_minutes_dimming || 0;
        ui['w-dim-pct']      = s.dimming_pct || 100;
        ui['w-base-dim-pct'] = s.base_dimming_pct || 30;
        ui['w-dali']         = !!(s.advanced_flags & 1);
        ui['w-alc']          = !!(s.advanced_flags & 2);
    }
    flow.set('ui_state', ui);
    flow.set('w__dirty', false);
}

const onlineMap = global.get('online_map') || {};
const online = onlineMap[serial] ? onlineMap[serial].online !== false : true;
const statusColor = online ? '#22c55e' : '#ef4444';

out[0] = { payload: `
<div style="background:#1e2937;padding:18px;border-radius:8px;margin-bottom:16px;">
    <div style="display:flex;align-items:center;gap:12px;margin-bottom:14px;">
        <div style="width:16px;height:16px;border-radius:50%;background:${statusColor};"></div>
        <span style="font-size:26px;font-weight:700;">${serial}</span>
        <span style="color:${statusColor};font-weight:700;">${online ? '● ONLINE' : '○ OFFLINE'}</span>
    </div>
    <div style="display:grid;grid-template-columns:120px 1fr;gap:8px;font-size:14.5px;line-height:1.6;">
        <div style="color:#64748b;">Model</div>     <div style="color:#e2e8f0;">${info.device_type || 'Phocos MPPT'} V${info.hw_version || '?'}</div>
        <div style="color:#64748b;">Produced</div>  <div style="color:#e2e8f0;">${info.production_date || '—'}</div>
        <div style="color:#64748b;">Zone</div>      <div style="color:#e2e8f0;">${dev.zone || 'default'}</div>
        <div style="color:#64748b;">Gateway</div>   <div style="color:#e2e8f0;">${dev.gateway_id || '—'}</div>
    </div>
</div>` };

const BAT  = ['Unknown', 'AGM', 'Liquid', 'LiFePO4', 'LFP High Temp', 'LFP Med Temp', 'LFP Low Temp'];
const MODE = ['Always On', 'D2D', 'DD', 'MN'];

out[17] = { payload: s ? `
<div style="background:#1e2937;padding:18px;border-radius:8px;">
    <div style="font-size:15px;font-weight:700;color:#e2e8f0;margin-bottom:16px;">DEVICE CONFIGURATION</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px 30px;font-size:14.5px;">
        <div><span style="color:#64748b;">Battery Type</span><br><strong>${BAT[s.battery_type] || s.battery_type}</strong></div>
        <div><span style="color:#64748b;">Capacity</span><br><strong>${s.capacity_ah} Ah</strong></div>
        <div><span style="color:#64748b;">LVD</span><br><strong>${(s.lvd_voltage_mv/1000).toFixed(1)} V</strong></div>
        <div><span style="color:#64748b;">LVD Mode</span><br><strong>${s.lvd_mode === 1 ? 'Voltage' : 'SOC'}</strong></div>
        <div><span style="color:#64748b;">Night Mode</span><br><strong>${MODE[s.night_mode] || s.night_mode}</strong></div>
        <div><span style="color:#64748b;">Evening</span><br><strong>${s.evening_minutes} min</strong></div>
        <div><span style="color:#64748b;">Morning</span><br><strong>${s.morning_minutes} min</strong></div>
        <div><span style="color:#64748b;">Night Thresh</span><br><strong>${(s.night_threshold_mv/1000).toFixed(1)} V</strong></div>
        <div><span style="color:#64748b;">Dim Mode</span><br><strong>${MODE[s.dimming_mode] || s.dimming_mode}</strong></div>
        <div><span style="color:#64748b;">Dimming</span><br><strong>${s.dimming_pct} %</strong></div>
        <div><span style="color:#64748b;">Base Dim</span><br><strong>${s.base_dimming_pct} %</strong></div>
        <div><span style="color:#64748b;">DALI</span><br><strong>${(s.advanced_flags & 1) ? '✅ On' : '❌ Off'}</strong></div>
        <div><span style="color:#64748b;">ALC</span><br><strong>${(s.advanced_flags & 2) ? '✅ On' : '❌ Off'}</strong></div>
    </div>
</div>` : `<div style="padding:80px 20px;text-align:center;color:#64748b;">No settings cached</div>` };

const ui = flow.get('ui_state');
if (s) {
    out[1]  = { payload: ui['w-bat-type'] };
    out[2]  = { payload: ui['w-cap-ah'] };
    out[3]  = { payload: ui['w-lvd-v'] };
    out[4]  = { payload: ui['w-lvd-mode'] };
    out[5]  = { payload: ui['w-night-mode'] };
    out[6]  = { payload: ui['w-eve-min'] };
    out[7]  = { payload: ui['w-morn-min'] };
    out[8]  = { payload: ui['w-night-thresh'] };
    out[9]  = { payload: ui['w-dim-mode'] };
    out[10] = { payload: ui['w-dim-eve-min'] };
    out[11] = { payload: ui['w-dim-morn-min'] };
    out[12] = { payload: ui['w-dim-pct'] };
    out[13] = { payload: ui['w-base-dim-pct'] };
    out[14] = { payload: ui['w-dali'] };
    out[15] = { payload: ui['w-alc'] };
}

node.send(out);
return null;

const ui = flow.get('ui_state') || {};
ui[msg.topic] = msg.payload;
flow.set('ui_state', ui);

// Mark as dirty so fn-on-device-select (from background) doesn't overwrite
flow.set('w__dirty', true);
return null;

if (msg.topic === 'send')   return [msg, null];
if (msg.topic === 'reload') return [null, msg];
return null;

const serial = flow.get('selected_serial');
if (!serial) return null;
msg.payload = serial;
return msg;

const serial = global.get('selected_serial');
const baseline = flow.get('baseline');
const ui = flow.get('ui_state') || {};

if (!serial) {
    node.error("No device selected");
    return null;
}
if (!baseline) {
    node.error("No baseline settings available for " + serial);
    return null;
}

const setSettings = {};

// Helper to check if value changed. 
// Note: UI values might be strings from dropdowns or booleans from switches.
const changed = (uiKey, baselineVal, transform) => {
    let uiVal = ui[uiKey];
    if (uiVal === undefined) return;

    let processed = transform ? transform(uiVal) : uiVal;

    // Compare numerically or strictly
    if (processed != baselineVal) {
        return processed;
    }
    return undefined;
};

const toInt = v => parseInt(v, 10);
const toMv  = v => Math.round(parseFloat(v) * 1000);
const toBoolInt = v => (v === true || v === 'true') ? 1 : 0;

let val;
if ((val = changed('w-bat-type', baseline.battery_type, toInt)) !== undefined) setSettings.battery_type = val;
if ((val = changed('w-cap-ah', baseline.capacity_ah, toInt)) !== undefined) setSettings.capacity_ah = val;
if ((val = changed('w-lvd-v', baseline.lvd_voltage_mv, toMv)) !== undefined) setSettings.lvd_voltage_mv = val;
if ((val = changed('w-lvd-mode', baseline.lvd_mode, toBoolInt)) !== undefined) setSettings.lvd_mode = val;
if ((val = changed('w-night-mode', baseline.night_mode, toInt)) !== undefined) setSettings.night_mode = val;
if ((val = changed('w-eve-min', baseline.evening_minutes, toInt)) !== undefined) setSettings.evening_minutes = val;
if ((val = changed('w-morn-min', baseline.morning_minutes, toInt)) !== undefined) setSettings.morning_minutes = val;
if ((val = changed('w-night-thresh', baseline.night_threshold_mv, toMv)) !== undefined) setSettings.night_threshold_mv = val;
if ((val = changed('w-dim-mode', baseline.dimming_mode, toInt)) !== undefined) setSettings.dimming_mode = val;
if ((val = changed('w-dim-eve-min', baseline.evening_minutes_dimming, toInt)) !== undefined) setSettings.evening_minutes_dimming = val;
if ((val = changed('w-dim-morn-min', baseline.morning_minutes_dimming, toInt)) !== undefined) setSettings.morning_minutes_dimming = val;
if ((val = changed('w-dim-pct', baseline.dimming_pct, toInt)) !== undefined) setSettings.dimming_pct = val;
if ((val = changed('w-base-dim-pct', baseline.base_dimming_pct, toInt)) !== undefined) setSettings.base_dimming_pct = val;

// Advanced flags diff
const oldFlags = baseline.advanced_flags || 0;
const newDali  = (ui['w-dali'] === true || ui['w-dali'] === 'true');
const newAlc   = (ui['w-alc'] === true || ui['w-alc'] === 'true');
let newFlags = oldFlags;
if (newDali) newFlags |= 1; else newFlags &= ~1;
if (newAlc)  newFlags |= 2; else newFlags &= ~2;

if (newFlags !== oldFlags) {
    setSettings.advanced_flags = newFlags;
}

const keys = Object.keys(setSettings);
if (keys.length === 0) {
    node.warn("No changes detected between UI and device for " + serial);
    return null;
}

const fleet = global.get('fleet') || {};
const dev = fleet[serial] || {};
const zone = dev.zone || 'default';
const gw = dev.gateway_id || 'unknown';

const requestId = serial + '_' + Date.now();
msg.topic = 'mppt/' + zone + '/' + gw + '/' + serial + '/cmd';
msg.payload = {
    serial,
    request_id: requestId,
    timestamp: Math.floor(Date.now() / 1000),
    set_settings: setSettings
};

const ts = new Date().toLocaleTimeString();
const entry = '<div style="font-size:12px;padding:4px 0;border-bottom:1px solid #334155">' +
    '<span style="color:#64748b">' + ts + '</span> ' +
    '<span style="color:#3b82f6;font-weight:600">SEND</span> ' +
    serial + ' — <span style="color:#eab308">' + keys.length + ' fields changed</span>' +
    '</div>';

flow.set('cmd_log', entry + (flow.get('cmd_log') || ''));
return msg;

var log = flow.get('cmd_log') || '<span style="color:#64748b;font-style:italic">No commands sent yet.</span>';
msg.payload = '<div style="font-family:monospace;max-height:260px;overflow-y:auto;font-size:12px">' + log + '</div>';
return msg;

const p = msg.topic.split('/');
const serial = p.length >= 4 ? p[3] : '?';
const ts = new Date().toLocaleTimeString();
const pl = msg.payload || {};

const ok = pl.ok === true || pl.ok === 'true';
const reason = pl.reason || '';
const reqId = pl.requestId || pl.request_id || '';

const color = ok ? '#4ade80' : '#f87171';
const label = ok ? 'ACK ✓' : 'ACK ✗';
const idStr = reqId ? ` <span style="color:#475569">[${reqId.split('_').pop()}]</span>` : '';

const entry =
    `<div style="font-size:12px;padding:4px 0;border-bottom:1px solid #1e293b">` +
    `<span style="color:#475569">${ts}</span> ` +
    `<span style="color:${color};font-weight:700">${label}</span> ` +
    `<span style="color:#94a3b8">${serial}</span>${idStr}` +
    (reason ? `<span style="color:#64748b"> — ${reason}</span>` : '') +
    `</div>`;

const log = flow.get('cmd_log') || '';
flow.set('cmd_log', entry + log);

if (ok) {
    // Clear the GLOBAL stage for this serial
    global.set('stage_' + serial, {});
    const currentSerial = flow.get('selected_serial');
    if (serial === currentSerial) {
        flow.set('w__dirty', false);
    }
}

msg.payload =
    `<div style="font-family:monospace;max-height:260px;overflow-y:auto;font-size:12px">` +
    flow.get('cmd_log') + '</div>';
return msg;

var fleet = global.get('fleet') || {};

var opts = Object.keys(fleet)
    .sort()
    .map(function(s) {
        var dev = fleet[s] || {};
        var zone = dev.zone || 'default';
        var onlineMap = global.get('online_map') || {};
        var isOnline = onlineMap[s] ? onlineMap[s].online !== false : true;
        var icon = isOnline ? ' ●' : ' ○';
        return {
            value: s,
            label: s + ' [' + zone + ']' + icon
        };
    });

opts.unshift({ value: "", label: "-- Select Device --" });

var optsStr = JSON.stringify(opts);
if (optsStr === context.get('lastOpts')) return null;
context.set('lastOpts', optsStr);

// To update options in Dashboard 2 ui-dropdown, send them in msg.options
msg.options = opts;
return msg;
